// styles.js

import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  homeContainer: {
    position: 'relative',
    zIndex: 0,
  },
  heroImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  section: {
    textAlign: 'center',
  },
  imageContainer: {
    position: 'relative',
    marginBottom: theme.spacing(2),
  },
  overlappingImage: {
    marginTop: '-25%', // Justera efter behov
    marginLeft: '25%',
  },
  image: {
    width: '100%',
    height: 'auto',
    objectFit: 'cover',
    borderRadius: theme.spacing(1), // Justera efter behov
  },
  textContainer: {
    padding: theme.spacing(2),
  },
}));

export default useStyles;
